import{_ as e,c as l,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"入門: AI スキルパッケージの基本 | Agent Skills","description":"Agent Skills の基本概念と 3 つのコアスキルパッケージを学びます。AI コーディングエージェントの機能を拡張し、開発効率を向上させる方法を習得できます。","frontmatter":{"title":"入門: AI スキルパッケージの基本 | Agent Skills","sidebarTitle":"入門","subtitle":"Agent Skills 入門","description":"Agent Skills の基本概念と 3 つのコアスキルパッケージを学びます。AI コーディングエージェントの機能を拡張し、開発効率を向上させる方法を習得できます。","tags":["入門","AI コーディングエージェント","Claude","スキルパッケージ"],"prerequisite":[]},"headers":[],"relativePath":"ja/vercel-labs/agent-skills/start/getting-started/index.md","filePath":"ja/vercel-labs/agent-skills/start/getting-started/index.md"}'),s={name:"ja/vercel-labs/agent-skills/start/getting-started/index.md"};function r(o,t,d,n,c,p){return i(),l("div",null,[...t[0]||(t[0]=[a(`<h1 id="agent-skills-入門" tabindex="-1">Agent Skills 入門 <a class="header-anchor" href="#agent-skills-入門" aria-label="Permalink to &quot;Agent Skills 入門&quot;">​</a></h1><h2 id="学習後、できること" tabindex="-1">学習後、できること <a class="header-anchor" href="#学習後、できること" aria-label="Permalink to &quot;学習後、できること&quot;">​</a></h2><ul><li>Agent Skills とは何か、それが AI コーディングエージェントの機能をどのように拡張するかを理解する</li><li>3 つのコアスキルパッケージの機能と使用シナリオを理解する</li><li>Agent Skills を使用して開発効率を向上させるタイミングを知る</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>日常的に Claude、Cursor、またはその他の AI コーディングエージェントを使用しているとき、以下の問題に遭遇するかもしれません：</p><ul><li>ベストプラクティスに従いたいが、覚えるべきルールがわからない</li><li>同様のデプロイ操作を頻繁に繰り返し、自動化したい</li><li>AI が生成するコードの品質にばらつきがあり、統一された基準がない</li></ul><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p><strong>Agent Skills はスキルパッケージシステム</strong>です——AI コーディングエージェントに拡張可能な「プラグイン」を提供します。各スキルには以下が含まれます：</p><ul><li><strong>SKILL.md</strong>：スキル定義ファイルで、AI エージェントにいつそのスキルを有効にするかを伝えます</li><li><strong>scripts/</strong>：補助スクリプト（デプロイスクリプトなど）で、具体的なタスクを実行します</li><li><strong>references/</strong>：補助ドキュメント（オプション）で、詳細な参考資料を提供します</li></ul><div class="tip custom-block"><p class="custom-block-title">デザイン理念</p><p>スキルは<strong>オンデマンドロード</strong>メカニズムを採用しています：スキル名と説明のみが起動時にロードされ、完全なコンテンツは AI が必要と判断したときに読み込まれます。これにより、コンテキストの使用量が削減され、効率が向上します。</p></div><h2 id="利用可能なスキルパッケージ" tabindex="-1">利用可能なスキルパッケージ <a class="header-anchor" href="#利用可能なスキルパッケージ" aria-label="Permalink to &quot;利用可能なスキルパッケージ&quot;">​</a></h2><p>プロジェクトは 3 つの主要なスキルパッケージを提供しており、それぞれが特定のシナリオに対応しています：</p><h3 id="react-best-practices" tabindex="-1">react-best-practices <a class="header-anchor" href="#react-best-practices" aria-label="Permalink to &quot;react-best-practices&quot;">​</a></h3><p>Vercel Engineering 基準に基づく React および Next.js のパフォーマンス最適化ガイド。影響レベル別に並べ替えられた 50 以上のルールが含まれています。</p><p><strong>使用シナリオ</strong>：</p><ul><li>新しい React コンポーネントまたは Next.js ページを記述する場合</li><li>コードのパフォーマンス問題をレビューする場合</li><li>バンドルサイズまたは読み込み時間を最適化する場合</li></ul><p><strong>カテゴリの概要</strong>：</p><ul><li>ウォーターフォールの排除（Critical）</li><li>バンドルサイズの最適化（Critical）</li><li>サーバーサイドのパフォーマンス（High）</li><li>クライアントサイドのデータフェッチ（Medium-High）</li><li>Re-render の最適化（Medium）</li><li>レンダリングのパフォーマンス（Medium）</li><li>JavaScript のマイクロ最適化（Low-Medium）</li><li>高度なパターン（Low）</li></ul><h3 id="web-design-guidelines" tabindex="-1">web-design-guidelines <a class="header-anchor" href="#web-design-guidelines" aria-label="Permalink to &quot;web-design-guidelines&quot;">​</a></h3><p>Web インターフェースデザインガイド監査。コードが 100 近いベストプラクティスに準拠しているかを確認します。</p><p><strong>使用シナリオ</strong>：</p><ul><li>プロンプト：&quot;Review my UI&quot;</li><li>アクセシビリティ（Accessibility）のチェック</li><li>デザインの一貫性の監査</li><li>パフォーマンスと UX のチェック</li></ul><p><strong>カテゴリの概要</strong>：</p><ul><li>アクセシビリティ（aria-labels、意味論的 HTML、キーボードハンドリング）</li><li>フォーカス状態（可視フォーカス、focus-visible モード）</li><li>フォーム（オートコンプリート、検証、エラーハンドリング）</li><li>アニメーション（prefers-reduced-motion、合成フレンドリーな変換）</li><li>画像（サイズ、遅延読み込み、alt テキスト）</li><li>タイポグラフィ、パフォーマンス、ナビゲーションなど</li></ul><h3 id="vercel-deploy-claimable" tabindex="-1">vercel-deploy-claimable <a class="header-anchor" href="#vercel-deploy-claimable" aria-label="Permalink to &quot;vercel-deploy-claimable&quot;">​</a></h3><p>アプリとウェブサイトをワンクリックで Vercel にデプロイし、プレビューリンクと所有権譲渡リンクを返します。</p><p><strong>使用シナリオ</strong>：</p><ul><li>プロンプト：&quot;Deploy my app&quot;</li><li>プロジェクトプレビューを迅速に共有する</li><li>設定不要、認証不要のデプロイ</li></ul><p><strong>コア機能</strong>：</p><ul><li>40 以上のフレームワークを自動検出（Next.js、Vite、Astro など）</li><li>プレビュー URL（リアルタイムサイト）とクレーム URL（所有権譲渡）を返す</li><li>静的 HTML プロジェクトを自動処理</li><li>アップロード時に <code>node_modules</code> と <code>.git</code> を除外</li></ul><h2 id="スキルの仕組み" tabindex="-1">スキルの仕組み <a class="header-anchor" href="#スキルの仕組み" aria-label="Permalink to &quot;スキルの仕組み&quot;">​</a></h2><p>Claude やその他の AI エージェントを使用しているとき、スキルの有効化フローは以下の通りです：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[ユーザーがタスクを入力] --&gt; B[AI がキーワードを検出&lt;br/&gt;Deploy、Review、Optimize など]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[スキルの説明を照合]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[SKILL.md の完全なコンテンツを読み込む]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[スクリプトを実行またはルールを適用]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[ユーザーに結果を出力]</span></span></code></pre></div><p><strong>フローの例</strong>：</p><ol><li><strong>ユーザー入力</strong>：&quot;Deploy my app&quot;</li><li><strong>AI 検出</strong>：キーワード &quot;Deploy&quot; を認識し、<code>vercel-deploy</code> スキルを照合</li><li><strong>スキル読み込み</strong>：<code>SKILL.md</code> の完全なコンテンツを読み込む</li><li><strong>デプロイ実行</strong>： <ul><li><code>deploy.sh</code> スクリプトを実行</li><li>フレームワークを検出（package.json を読み込み）</li><li>プロジェクトを tarball にパッケージ化</li><li>Vercel API にアップロード</li></ul></li><li><strong>結果返却</strong>：<div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;previewUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://skill-deploy-abc123.vercel.app&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claimUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://vercel.com/claim-deployment?code=...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li></ol><h2 id="使用タイミング" tabindex="-1">使用タイミング <a class="header-anchor" href="#使用タイミング" aria-label="Permalink to &quot;使用タイミング&quot;">​</a></h2><p>Agent Skills を使用する最適なタイミング：</p><table tabindex="0"><thead><tr><th>シナリオ</th><th>使用するスキル</th><th>トリガープロンプトの例</th></tr></thead><tbody><tr><td>React コンポーネントを記述</td><td>react-best-practices</td><td>&quot;Review this React component for performance issues&quot;</td></tr><tr><td>Next.js ページを最適化</td><td>react-best-practices</td><td>&quot;Help me optimize this Next.js page&quot;</td></tr><tr><td>UI の品質をチェック</td><td>web-design-guidelines</td><td>&quot;Check accessibility of my site&quot;</td></tr><tr><td>プロジェクトをデプロイ</td><td>vercel-deploy-claimable</td><td>&quot;Deploy my app to production&quot;</td></tr></tbody></table><h2 id="セキュリティモデル" tabindex="-1">セキュリティモデル <a class="header-anchor" href="#セキュリティモデル" aria-label="Permalink to &quot;セキュリティモデル&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">セキュリティについての説明</p><ul><li><strong>ローカル実行</strong>：すべてのスキルはローカルで実行され、Vercel デプロイ API を除きサードパーティサービスへデータはアップロードされません</li><li><strong>オンデマンド有効化</strong>：スキルは AI が関連すると判断した場合のみ詳細コンテンツを読み込むため、プライバシーの漏洩リスクが低減されます</li><li><strong>オープンソースで透明</strong>：すべてのスキルとスクリプトはオープンソースで監査可能です</li></ul></div><h2 id="注意点" tabindex="-1">注意点 <a class="header-anchor" href="#注意点" aria-label="Permalink to &quot;注意点&quot;">​</a></h2><h3 id="スキルが有効にならない" tabindex="-1">スキルが有効にならない <a class="header-anchor" href="#スキルが有効にならない" aria-label="Permalink to &quot;スキルが有効にならない&quot;">​</a></h3><p>スキルが有効にならない場合、以下を確認してください：</p><ul><li>プロンプトに十分なキーワード（&quot;Deploy&quot;、&quot;Review&quot; など）が含まれているか</li><li>スキルが <code>~/.claude/skills/</code> ディレクトリに正しくインストールされているか</li><li>claude.ai を使用している場合、スキルがプロジェクトナレッジベースに追加されているか</li></ul><h3 id="ネットワーク権限" tabindex="-1">ネットワーク権限 <a class="header-anchor" href="#ネットワーク権限" aria-label="Permalink to &quot;ネットワーク権限&quot;">​</a></h3><p>一部のスキルはネットワークアクセスが必要です：</p><ul><li><code>vercel-deploy-claimable</code> は Vercel デプロイ API にアクセスする必要があります</li><li><code>web-design-guidelines</code> は GitHub から最新ルールをプルする必要があります</li></ul><p><strong>解決策</strong>：claude.ai/settings/capabilities で必要なドメインを追加してください。</p><h2 id="この授業のまとめ" tabindex="-1">この授業のまとめ <a class="header-anchor" href="#この授業のまとめ" aria-label="Permalink to &quot;この授業のまとめ&quot;">​</a></h2><p>Agent Skills は AI コーディングエージェント向けのスキルパッケージシステムで、以下を提供します：</p><ul><li><strong>react-best-practices</strong>：React/Next.js パフォーマンス最適化ルール 50 以上</li><li><strong>web-design-guidelines</strong>：Web デザインベストプラクティス 100 近く</li><li><strong>vercel-deploy-claimable</strong>：Vercel へのワンクリックデプロイ</li></ul><p>スキルはオンデマンドロードメカニズムを採用し、コンテキストの使用量を最小限に抑えます。インストール後、AI エージェントは関連するタスクで対応するスキルを自動的に有効にします。</p><h2 id="次の授業の予告" tabindex="-1">次の授業の予告 <a class="header-anchor" href="#次の授業の予告" aria-label="Permalink to &quot;次の授業の予告&quot;">​</a></h2><blockquote><p>次の授業では <strong><a href="./../installation/">Agent Skills のインストール</a></strong> を学びます。</p><p>学べること：</p><ul><li>2 つのインストール方法：Claude Code と claude.ai</li><li>ネットワーク権限の設定</li><li>スキルが正しくインストールされているかの確認</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日時：2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>スキルパッケージリスト</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L7-L80" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>7-80</td></tr><tr><td>スキル構造の説明</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L103-L110" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>103-110</td></tr><tr><td>AGENTS.md 仕様</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>全文</td></tr><tr><td>スキルディレクトリ構造</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L11-L20" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>11-20</td></tr><tr><td>SKILL.md フォーマット</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L29-L68" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>29-68</td></tr><tr><td>スキルパッケージ化コマンド</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L93-L96" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>93-96</td></tr><tr><td>ユーザーインストール方法</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L98-L110" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>98-110</td></tr><tr><td>オンデマンドロードメカニズム</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L72-L78" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>72-78</td></tr><tr><td>ビルドツールスクリプト</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/package.json" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/package.json</code></a></td><td>全文</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li>ハードコーディングされた定数はありません</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>build.ts</code>：AGENTS.md とテストケースの構築</li><li><code>validate.ts</code>：ルールファイルの整合性の検証</li><li><code>extract-tests.ts</code>：ルールからテストケースを抽出</li></ul></details>`,57)])])}const u=e(s,[["render",r]]);export{g as __pageData,u as default};
